module lfsr_8bit(  
    input clk,  
    input reset,  
    output reg lfsr_out  
);  
    reg [7:0] counter;  
    wire feedback;  

    // Feedback polynomial: x^8 + x^6 + x^5 + x^4 + 1  
    assign feedback = counter[7] ^ counter[5] ^ counter[4] ^ counter[6];  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            counter <= 8'b1; // Initialize to a non-zero value  
        end else begin  
            counter <= {counter[6:0], feedback};  
        end  
    end  

    always @(posedge clk) begin  
        lfsr_out <= counter[7];  
    end  
endmodule
